import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CircularProgress } from '@mui/material';
import response from './response.json';

interface OrderTrackingData {
  order: {
    orderId: string;
    status: string;
    eta: string;
  };
  deliveryProgress: {
    stage: string;
    completed: boolean;
  }[];
  currentLocation: string;
}

export default function Widget() {
  const orderTrackingData = response.data as OrderTrackingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Order Tracking
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Order ID: {orderTrackingData.order.orderId}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Status: {orderTrackingData.order.status}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              ETA: {new Date(orderTrackingData.order.eta).toLocaleString()}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {orderTrackingData.deliveryProgress.map((progress, index) => (
              <Chip
                key={index}
                label={progress.stage}
                color={progress.completed ? 'primary' : 'default'}
                variant={progress.completed ? 'filled' : 'outlined'}
                sx={{ fontSize: '11px' }}
              />
            ))}
          </Stack>

          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <CircularProgress size={20} sx={{ color: '#FFC107', mr: 1 }} />
            <Typography variant="body2" color="text.secondary">
              Current Location: {orderTrackingData.currentLocation}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
